tool_calls:
awk '
function trim(s){ sub(/^[[:space:]]+/,"",s); sub(/[[:space:]]+$/,"",s); return s }
function add_section(sec){ if (!(sec in seen_sec)) { seen_sec[sec]=1; sec_order[++nsec]=sec } }
function add_key(sec,key){ idx=sec SUBSEP key; if (!(idx in seen_key)) { seen_key[idx]=1; key_order[sec,++key_count[sec]]=key } }
BEGIN { sec="" }
FNR==1 { file_index++ }
/^[[:space:]]*$/ { next }
/^[[:space:]]*\[/ {
  line=$0
  sub(/^[[:space:]]*\[/,"",line); sub(/\][[:space:]]*$/,"",line)
  sec=trim(line)
  add_section(sec)
  next
}
{
  pos=index($0,"=")
  if (pos>0 && sec != "") {
    key=trim(substr($0,1,pos-1))
    val=trim(substr($0,pos+1))
    add_key(sec,key)
    values[sec,key]=val
  }
}
END {
  for (i=1; i<=nsec; i++) {
    sec=sec_order[i]
    print "[" sec "]"
    for (j=1; j<=key_count[sec]; j++) {
      key=key_order[sec,j]
      print key "=" values[sec,key]
    }
    if (i<nsec) print ""
  }
}
' /config/defaults.ini /config/custom.ini > /config/merged.ini
cat /config/merged.ini

